import React, { useState } from "react";
import { 
  Users, Stethoscope, Calendar, CreditCard, 
  LogOut, HeartPulse, Pill, Layout, FileText, Database
} from "lucide-react";
import "./index.css";

function App() {
  const [user, setUser] = useState(null); // { role, username }
  const [activeTab, setActiveTab] = useState("dashboard");
  const [loading, setLoading] = useState(false);
  const [loginForm, setLoginForm] = useState({ username: "", password: "" });

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);

    setTimeout(() => {
      const u = loginForm.username.toLowerCase();
      const p = loginForm.password.toLowerCase();

      if (u === "patient" && p === "patient") {
        setUser({ role: "patient", username: "Alice Smith", patient_id: 1 });
        setActiveTab("dashboard");
      } else if (u === "doctor" && p === "doctor") {
        setUser({ role: "doctor", username: "Dr. Bob Johnson", doctor_id: 101 });
        setActiveTab("dashboard");
      } else {
        alert("ACCESS DENIED: Use 'patient/patient' or 'doctor/doctor'");
      }
      setLoading(false);
    }, 500);
  };

  const logout = () => {
    setUser(null);
    setLoginForm({ username: "", password: "" });
  };

  if (!user) {
    return (
      <div className="login-screen">
        <div className="login-card">
          <div className="login-card-header">
            <HeartPulse size={48} color="var(--text-primary)" strokeWidth={3} />
            <h2>MediCore</h2>
            <p>AUTHORIZED PERSONNEL ONLY</p>
          </div>
          <form onSubmit={handleLogin}>
            <div className="input-group">
              <label>IDENTIFIER</label>
              <input 
                type="text" 
                placeholder="USERNAME"
                value={loginForm.username}
                onChange={(e) => setLoginForm({ ...loginForm, username: e.target.value })}
                required
              />
            </div>
            <div className="input-group">
              <label>PASSCODE</label>
              <input 
                type="password" 
                placeholder="PASSWORD"
                value={loginForm.password}
                onChange={(e) => setLoginForm({ ...loginForm, password: e.target.value })}
                required
              />
            </div>
            <button className="btn" type="submit" style={{ width: "100%", marginTop: 16 }} disabled={loading}>
              {loading ? "VERIFYING..." : "ENTER SYSTEM"} <LogOut size={18} />
            </button>
          </form>
          <div style={{ textAlign: "center", marginTop: 32 }}>
             <p style={{ fontSize: "0.80rem", fontWeight: 600, color: "var(--text-secondary)" }}>HINT: patient/patient OR doctor/doctor</p>
          </div>
        </div>
      </div>
    );
  }

  // Define sidebar navigation based on role
  const getNavLinks = () => {
    if (user.role === "patient") {
      return [
        { id: "dashboard", label: "My Overview", icon: HeartPulse },
        { id: "appointments", label: "Appointments", icon: Calendar },
        { id: "prescriptions", label: "Prescriptions", icon: Pill },
        { id: "billing", label: "Bills & Payments", icon: CreditCard }
      ];
    } else if (user.role === "doctor") {
      return [
        { id: "dashboard", label: "Doctor Dashboard", icon: Stethoscope },
        { id: "schedule", label: "My Schedule", icon: Calendar },
        { id: "consultations", label: "Consultations", icon: FileText },
        { id: "admissions", label: "Inpatient Wards", icon: Layout }
      ];
    }
  };

  return (
    <div className="app-container">
      {/* Sidebar Navigation */}
      <aside className="sidebar">
        <div className="brand">
          {user.role === "doctor" ? <Stethoscope size={28} strokeWidth={3} /> : <HeartPulse size={28} strokeWidth={3} />}
          MediCore
        </div>

        <nav className="nav-links">
          {getNavLinks().map(mod => (
            <button 
              key={mod.id}
              className={`nav-item ${activeTab === mod.id ? "active" : ""}`}
              onClick={() => setActiveTab(mod.id)}
            >
              <mod.icon size={20} /> {mod.label}
            </button>
          ))}
        </nav>

        <div style={{ marginTop: "auto", borderTop: "2px solid var(--border-color)", paddingTop: 24 }}>
          <button className="btn btn-outline" onClick={logout} style={{ width: "100%" }}>
            <LogOut size={18} /> SIGN OUT
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="main-content">
        <header className="header">
          <div>
            <h1>{getNavLinks().find(m => m.id === activeTab)?.label?.toUpperCase()}</h1>
            <p>SECURE PORTAL INTERFACE</p>
          </div>
          <div className="user-profile">
             <div className="user-info">
                <strong>{user.username}</strong>
                <p className="role-badge">ROLE: {user.role.toUpperCase()}</p>
             </div>
             <div className="avatar">
               {user.username.charAt(0).toUpperCase()}
             </div>
          </div>
        </header>

        {/* ==================================================== */}
        {/* PATIENT DASHBOARD VIEWS                              */}
        {/* ==================================================== */}

        {user.role === "patient" && activeTab === "dashboard" && (
          <div className="grid-cards">
            <div className="solid-card">
              <h3 className="form-header"><FileText size={24} /> NEXT APPOINTMENT</h3>
              <p><strong>Date:</strong> 2026-04-10 10:00 AM</p>
              <p><strong>Doctor:</strong> Dr. Bob Johnson (Cardiology)</p>
              <span className="status-badge" style={{ marginTop: 12, display: "inline-block" }}>UPCOMING</span>
            </div>
            <div className="solid-card">
              <h3 className="form-header"><Pill size={24} /> ACTIVE PRESCRIPTIONS</h3>
              <p>1x Amoxicillin 500mg</p>
              <p>2x Ibuprofen 200mg</p>
            </div>
            <div className="solid-card">
              <h3 className="form-header"><CreditCard size={24} /> OUTSTANDING BALANCE</h3>
              <div className="stat-value">$150.00</div>
              <button className="btn" style={{ marginTop: 16 }} onClick={() => setActiveTab("billing")}>PAY NOW</button>
            </div>
          </div>
        )}

        {user.role === "patient" && activeTab === "appointments" && (
           <div className="solid-card">
             <h2 className="form-header">MY APPOINTMENT HISTORY</h2>
             <div className="list-item">
                <div>
                   <strong>DR. BOB JOHNSON</strong>
                   <p>Cardiology Consultation - 2026-03-15 09:30 AM</p>
                </div>
                <span className="status-badge">COMPLETED</span>
             </div>
             <div className="list-item">
                <div>
                   <strong>DR. ALICE SMITH</strong>
                   <p>General Checkup - 2026-04-10 10:00 AM</p>
                </div>
                <span className="status-badge">UPCOMING</span>
             </div>
           </div>
        )}

        {user.role === "patient" && activeTab === "prescriptions" && (
           <div className="solid-card">
             <h2 className="form-header">MEDICATION DIRECTORY</h2>
             <table style={{ width: "100%", textAlign: "left", borderCollapse: "collapse" }}>
               <thead>
                 <tr style={{ borderBottom: "2px solid #000" }}>
                   <th style={{ padding: 12 }}>MEDICINE ID</th>
                   <th style={{ padding: 12 }}>NAME</th>
                   <th style={{ padding: 12 }}>DOSAGE</th>
                 </tr>
               </thead>
               <tbody>
                 <tr style={{ borderBottom: "1px solid #ccc" }}>
                   <td style={{ padding: 12 }}>MED-001</td>
                   <td style={{ padding: 12 }}>Amoxicillin</td>
                   <td style={{ padding: 12 }}>500mg - 2x daily</td>
                 </tr>
                 <tr style={{ borderBottom: "1px solid #ccc" }}>
                   <td style={{ padding: 12 }}>MED-045</td>
                   <td style={{ padding: 12 }}>Ibuprofen</td>
                   <td style={{ padding: 12 }}>200mg - As needed</td>
                 </tr>
               </tbody>
             </table>
           </div>
        )}

        {user.role === "patient" && activeTab === "billing" && (
           <div className="solid-card">
             <h2 className="form-header">INVOICES & PAYMENTS</h2>
             <div className="list-item">
                <div>
                   <strong>CONSULTATION BILL #442</strong>
                   <p>Dr. Bob Johnson - 2026-03-15</p>
                </div>
                <div style={{ textAlign: "right" }}>
                  <strong>$150.00</strong><br/>
